function loadPublicConfig() {
  try {
    const raw = localStorage.getItem('bitweb-public-config');
    if (!raw) return { ...DEFAULT_PUBLIC_CONFIG };
    const parsed = JSON.parse(raw);
    return normalizePublicConfig({ ...DEFAULT_PUBLIC_CONFIG, ...parsed });
  } catch {
    return { ...DEFAULT_PUBLIC_CONFIG };
  }
}

function savePublicConfig(cfg) {
  localStorage.setItem('bitweb-public-config', JSON.stringify(cfg));
}

function normalizePublicConfig(cfg) {
  const out = { ...DEFAULT_PUBLIC_CONFIG, ...cfg };
  out.electrumUrl = String(out.electrumUrl || DEFAULT_PUBLIC_CONFIG.electrumUrl).trim();
  out.explorerUrl = String(out.explorerUrl || DEFAULT_PUBLIC_CONFIG.explorerUrl).trim().replace(/\/+$/, '');
  out.bech32 = String(out.bech32 || DEFAULT_PUBLIC_CONFIG.bech32).trim();
  out.pubKeyHash = toInt(out.pubKeyHash, DEFAULT_PUBLIC_CONFIG.pubKeyHash);
  out.scriptHash = toInt(out.scriptHash, DEFAULT_PUBLIC_CONFIG.scriptHash);
  out.wif = toInt(out.wif, DEFAULT_PUBLIC_CONFIG.wif);
  out.xpubVersion = toHexNumber(out.xpubVersion, DEFAULT_PUBLIC_CONFIG.xpubVersion);
  out.xprvVersion = toHexNumber(out.xprvVersion, DEFAULT_PUBLIC_CONFIG.xprvVersion);
  out.coinType = toInt(out.coinType, DEFAULT_PUBLIC_CONFIG.coinType);
  out.account = toInt(out.account, DEFAULT_PUBLIC_CONFIG.account);
  out.addressType = Object.hasOwn(PURPOSE_BY_ADDRESS_TYPE, out.addressType) ? out.addressType : DEFAULT_PUBLIC_CONFIG.addressType;
  out.feeRate = Math.max(1, Number(out.feeRate || DEFAULT_PUBLIC_CONFIG.feeRate));
  out.gapLimit = Math.max(1, toInt(out.gapLimit, DEFAULT_PUBLIC_CONFIG.gapLimit));
  out.maxScan = Math.max(out.gapLimit, toInt(out.maxScan, DEFAULT_PUBLIC_CONFIG.maxScan));
  return out;
}

function toInt(value, fallback) {
  const n = Number.parseInt(String(value), 10);
  return Number.isFinite(n) ? n : fallback;
}

function toHexNumber(value, fallback) {
  if (typeof value === 'number' && Number.isFinite(value)) return value >>> 0;
  const s = String(value || '').trim().replace(/^0x/i, '');
  if (!s) return fallback >>> 0;
  const n = Number.parseInt(s, 16);
  return Number.isFinite(n) ? (n >>> 0) : (fallback >>> 0);
}

function hex32(value) {
  return (value >>> 0).toString(16).padStart(8, '0').toUpperCase();
}

function bytesToHexLower(bytes) {
  return bytesToHex(bytes);
}

function hexToBytesSafe(hex) {
  return hexToBytes(String(hex).trim());
}

function bytesToReversedHex(bytes) {
  const copy = bytes.slice();
  copy.reverse();
  return bytesToHex(copy);
}

function cryptoRandomBytes(length) {
  const out = new Uint8Array(length);
  globalThis.crypto.getRandomValues(out);
  return out;
}

function reverseBytes(bytes) {
  const out = bytes.slice();
  out.reverse();
  return out;
}

function electrumScripthash(scriptBytes) {
  return bytesToHex(reverseBytes(sha256(scriptBytes)));
}

function escapeHtml(value) {
  return String(value)
    .replaceAll('&', '&amp;')
    .replaceAll('<', '&lt;')
    .replaceAll('>', '&gt;')
    .replaceAll('"', '&quot;')
    .replaceAll("'", '&#39;');
}

function satsToCoinsString(sats) {
  const negative = sats < 0n;
  let x = negative ? -sats : sats;
  const whole = x / 100000000n;
  const frac = (x % 100000000n).toString().padStart(8, '0').replace(/0+$/, '');
  const body = frac.length ? `${whole.toString()}.${frac}` : whole.toString();
  return negative ? `-${body}` : body;
}

function coinsToSats(value) {
  const s = String(value).trim();
  if (!s) throw new Error('Amount is required');
  if (!/^\d+(\.\d{1,8})?$/.test(s)) throw new Error('Amount must have up to 8 decimals');
  const [whole, frac = ''] = s.split('.');
  return BigInt(whole) * 100000000n + BigInt((frac + '00000000').slice(0, 8));
}

function formatTimestamp(value) {
  if (!value) return '—';
  const d = new Date(value * 1000);
  return d.toLocaleString();
}

function truncateMiddle(text, left = 6, right = 6) {
  const s = String(text);
  if (s.length <= left + right + 3) return s;
  return `${s.slice(0, left)}…${s.slice(-right)}`;
}

function purposeForType(type) {
  return PURPOSE_BY_ADDRESS_TYPE[type] || PURPOSE_BY_ADDRESS_TYPE.p2wpkh;
}

function networkFromConfig(cfg) {
  return {
    bech32: cfg.bech32,
    pubKeyHash: cfg.pubKeyHash,
    scriptHash: cfg.scriptHash,
    wif: cfg.wif,
  };
}

function versionsFromConfig(cfg) {
  return {
    private: cfg.xprvVersion >>> 0,
    public: cfg.xpubVersion >>> 0,
  };
}

function accountPath(cfg) {
  return `m/${purposeForType(cfg.addressType)}'/${cfg.coinType}'/${cfg.account}'`;
}

function paymentForPubKey(pubKey, cfg) {
  const network = networkFromConfig(cfg);
  if (cfg.addressType === 'p2pkh') {
    return btc.p2pkh(pubKey, network);
  }
  if (cfg.addressType === 'p2sh-p2wpkh') {
    const witness = btc.p2wpkh(pubKey, network);
    return btc.p2sh(witness, network);
  }
  return btc.p2wpkh(pubKey, network);
}

function deriveAccountRoot(seedBytes, cfg) {
  const root = HDKey.fromMasterSeed(seedBytes, versionsFromConfig(cfg));
  return root.derive(accountPath(cfg));
}

function deriveAddressRecord(accountRoot, branch, index, cfg) {
  const node = accountRoot.deriveChild(branch).deriveChild(index);
  const privKey = node.privateKey;
  const pubKey = node.publicKey;
  if (!pubKey) throw new Error('Cannot derive public key');
  const payment = paymentForPubKey(pubKey, cfg);
  const script = payment.script;
  const redeemScript = payment.redeemScript ?? null;
  const address = payment.address;
  if (!address) throw new Error('Cannot derive address');
  return {
    branch,
    index,
    path: `${accountPath(cfg)}/${branch}/${index}`,
    node,
    privKey,
    pubKey,
    payment,
    address,
    script,
    redeemScript,
    scripthash: electrumScripthash(script),
    history: [],
    unspent: [],
  };
}

function isUsedRecord(rec) {
  return (rec.history && rec.history.length > 0) || (rec.unspent && rec.unspent.length > 0);
}

function normalizeElectrumList(result) {
  if (Array.isArray(result)) return result;
  if (!result) return [];
  return Array.isArray(result.result) ? result.result : [];
}

function normalizeElectrumBalance(result) {
  const obj = result && typeof result === 'object' ? result : {};
  const confirmed = BigInt(obj.confirmed ?? 0);
  const unconfirmed = BigInt(obj.unconfirmed ?? 0);
  return { confirmed, unconfirmed };
}

function normalizeTxId(txid) {
  if (typeof txid === 'string') return txid;
  if (txid instanceof Uint8Array) return bytesToHex(txid);
  return String(txid);
}

function normalizeExplorerBase(url) {
  return String(url || '').trim().replace(/\/+$/, '');
}

class ElectrumClient {
  constructor(url) {
    this.url = url;
    this.ws = null;
    this.id = 0;
    this.pending = new Map();
    this.subscriptions = new Map();
    this.connected = false;
    this.serverInfo = null;
  }

  async connect() {
    if (this.ws && (this.ws.readyState === WebSocket.OPEN || this.ws.readyState === WebSocket.CONNECTING)) {
      return;
    }

    const ws = new WebSocket(this.url);
    this.ws = ws;
    let settled = false;

    const cleanup = () => {
      if (timer) clearTimeout(timer);
      if (ws) {
        ws.onopen = null;
        ws.onerror = null;
        ws.onclose = null;
        ws.onmessage = null;
      }
    };

    const rejectPending = (reason) => {
      for (const [id, pending] of this.pending) {
        pending.reject(reason);
      }
      this.pending.clear();
    };

    const timer = setTimeout(() => {
      if (settled) return;
      settled = true;
      cleanup();
      if (this.ws === ws) this.ws = null;
      rejectPending(new Error('Electrum connection timed out'));
    }, 15000);

    await new Promise((resolve, reject) => {
      const finishReject = (err) => {
        if (settled) return;
        settled = true;
        cleanup();
        if (this.ws === ws) this.ws = null;
        reject(err);
      };

      const finishResolve = () => {
        if (settled) return;
        settled = true;
        cleanup();
        resolve();
      };

      ws.onmessage = (event) => this.handleMessage(event.data);
      ws.onclose = () => {
        this.connected = false;
        this.serverInfo = null;
        rejectPending(new Error('Electrum connection closed'));
        if (!settled) finishReject(new Error('Electrum connection closed'));
      };
      ws.onerror = () => {
        if (settled) return;
        rejectPending(new Error('Electrum websocket error'));
        finishReject(new Error('Electrum websocket error'));
      };
      ws.onopen = async () => {
        try {
          if (this.ws !== ws) return;
          const info = await this.call('server.version', [APP_NAME, ['1.4', '1.5']]);
          this.serverInfo = info;
          this.connected = true;
          finishResolve();
        } catch (err) {
          finishReject(err);
        }
      };
    });
  }

  close() {
    if (this.ws) {
      try {
        this.ws.close();
      } catch {}
    }
    this.connected = false;
    this.ws = null;
  }

  send(method, params) {
    if (!this.ws || this.ws.readyState !== WebSocket.OPEN) {
      throw new Error('Electrum websocket is not open');
    }
    this.ws.send(JSON.stringify({ jsonrpc: '2.0', id: ++this.id, method, params }));
    return this.id;
  }

  call(method, params = []) {
    return new Promise((resolve, reject) => {
      const id = ++this.id;
      const payload = { jsonrpc: '2.0', id, method, params };
      this.pending.set(id, { resolve, reject });
      try {
        this.ws.send(JSON.stringify(payload));
      } catch (err) {
        this.pending.delete(id);
        reject(err);
      }
    });
  }

  async ping() {
    return await this.call('server.ping', []);
  }

  async getHistory(scripthash) {
    return normalizeElectrumList(await this.call('blockchain.scripthash.get_history', [scripthash]));
  }

  async getBalance(scripthash) {
    return normalizeElectrumBalance(await this.call('blockchain.scripthash.get_balance', [scripthash]));
  }

  async listUnspent(scripthash) {
    return normalizeElectrumList(await this.call('blockchain.scripthash.listunspent', [scripthash]));
  }

  async getTransaction(txid) {
    const raw = await this.call('blockchain.transaction.get', [txid, false]);
    if (typeof raw !== 'string') throw new Error('Unexpected transaction payload');
    return raw;
  }

  async broadcast(txHex) {
    const res = await this.call('blockchain.transaction.broadcast', [txHex]);
    return typeof res === 'string' ? res : String(res);
  }

  async subscribeScripthash(scripthash, onChange) {
    const status = await this.call('blockchain.scripthash.subscribe', [scripthash]);
    this.subscriptions.set(scripthash, onChange);
    return status;
  }

  async unsubscribeScripthash(scripthash) {
    this.subscriptions.delete(scripthash);
    try {
      return await this.call('blockchain.scripthash.unsubscribe', [scripthash]);
    } catch {
      return false;
    }
  }

  handleMessage(data) {
    let msg;
    try {
      msg = JSON.parse(data);
    } catch {
      return;
    }
    if (msg && Object.hasOwn(msg, 'id')) {
      const pending = this.pending.get(msg.id);
      if (!pending) return;
      this.pending.delete(msg.id);
      if (msg.error) {
        const err = new Error(msg.error.message || 'Electrum error');
        err.code = msg.error.code;
        err.data = msg.error.data;
        pending.reject(err);
      } else {
        pending.resolve(msg.result);
      }
      return;
    }
    if (msg && msg.method && Array.isArray(msg.params)) {
      if (msg.method === 'blockchain.scripthash.subscribe' && msg.params.length >= 2) {
        const [scripthash, status] = msg.params;
        const cb = this.subscriptions.get(scripthash);
        if (cb) cb(status);
      }
      if (msg.method === 'blockchain.headers.subscribe') {
        // no-op; can be extended later
      }
    }
  }
}

