async function hasVault() {
  const db = await openDb();
  return await new Promise((resolve, reject) => {
    const tx = db.transaction(DB_STORE, 'readonly');
    const req = tx.objectStore(DB_STORE).get(VAULT_ID);
    req.onsuccess = () => resolve(Boolean(req.result));
    req.onerror = () => reject(req.error);
  });
}

async function openDb() {
  return await new Promise((resolve, reject) => {
    const req = indexedDB.open(DB_NAME, 1);
    req.onupgradeneeded = () => {
      const db = req.result;
      if (!db.objectStoreNames.contains(DB_STORE)) {
        db.createObjectStore(DB_STORE);
      }
    };
    req.onsuccess = () => resolve(req.result);
    req.onerror = () => reject(req.error || new Error('IndexedDB open failed'));
  });
}

async function saveVault(vault) {
  const db = await openDb();
  await new Promise((resolve, reject) => {
    const tx = db.transaction(DB_STORE, 'readwrite');
    tx.objectStore(DB_STORE).put(vault, VAULT_ID);
    tx.oncomplete = () => resolve();
    tx.onerror = () => reject(tx.error);
  });
  appState.vaultExists = true;
}

async function loadVault() {
  const db = await openDb();
  return await new Promise((resolve, reject) => {
    const tx = db.transaction(DB_STORE, 'readonly');
    const req = tx.objectStore(DB_STORE).get(VAULT_ID);
    req.onsuccess = () => resolve(req.result || null);
    req.onerror = () => reject(req.error);
  });
}

async function deleteVault() {
  const db = await openDb();
  await new Promise((resolve, reject) => {
    const tx = db.transaction(DB_STORE, 'readwrite');
    tx.objectStore(DB_STORE).delete(VAULT_ID);
    tx.oncomplete = () => resolve();
    tx.onerror = () => reject(tx.error);
  });
  appState.vaultExists = false;
}

async function encryptVaultRecord(password, record) {
  const salt = cryptoRandomBytes(16);
  const key = await scryptAsync(password, salt, DEFAULT_SCRYPT);
  const cipher = managedNonce(gcm)(key);
  const plaintext = te.encode(JSON.stringify(record));
  const ciphertext = cipher.encrypt(plaintext);
  key.fill(0);
  return {
    version: 1,
    kdf: 'scrypt',
    scrypt: DEFAULT_SCRYPT,
    salt: bytesToHexLower(salt),
    ciphertext: bytesToHexLower(ciphertext),
  };
}

async function decryptVaultRecord(vault, password) {
  if (!vault || vault.version !== 1 || vault.kdf !== 'scrypt') {
    throw new Error('Unsupported vault format');
  }
  const salt = hexToBytesSafe(vault.salt);
  const ciphertext = hexToBytesSafe(vault.ciphertext);
  const key = await scryptAsync(password, salt, vault.scrypt || DEFAULT_SCRYPT);
  const cipher = managedNonce(gcm)(key);
  const plaintext = cipher.decrypt(ciphertext);
  key.fill(0);
  const json = td.decode(plaintext);
  plaintext.fill(0);
  return JSON.parse(json);
}

function clearSecrets() {
  if (appState.root?.wipePrivateData) appState.root.wipePrivateData();
  if (appState.accountRoot?.wipePrivateData) appState.accountRoot.wipePrivateData();
  appState.root = null;
  appState.accountRoot = null;
  appState.mnemonic = '';
  appState.bip39Passphrase = '';
  appState.generatedMnemonic = '';
  appState.externalRecords = [];
  appState.changeRecords = [];
  appState.utxos = [];
  appState.balance = { confirmed: 0n, unconfirmed: 0n };
  appState.explorerAddressInfo = null;
  appState.explorerAddressTxs = [];
  appState.selectedAddressDetail = null;
  appState.nextExternalIndex = 0;
  appState.nextChangeIndex = 0;
}

async function unlockWithWalletData(walletData, vaultPassword) {
  const cfg = normalizePublicConfig(walletData.config || appState.publicConfig);
  appState.publicConfig = cfg;
  savePublicConfig(cfg);

  const mnemonic = String(walletData.mnemonic || '').trim();
  const passphrase = String(walletData.bip39Passphrase || '');
  if (!bip39.validateMnemonic(mnemonic, wordlist)) {
    throw new Error('Invalid mnemonic');
  }

  const seed = bip39.mnemonicToSeedSync(mnemonic, passphrase);
  const root = HDKey.fromMasterSeed(seed, versionsFromConfig(cfg));
  seed.fill(0);
  const accountRoot = root.derive(accountPath(cfg));

  clearSecrets();
  appState.root = root;
  appState.accountRoot = accountRoot;
  appState.masterFingerprint = root.fingerprint;
  appState.mnemonic = mnemonic;
  appState.bip39Passphrase = passphrase;
  appState.walletName = walletData.walletName || 'Main wallet';
  appState.unlocked = true;

  await connectElectrum();
  await syncWallet();
}

async function connectElectrum() {
  try {
    if (!appState.electrum) {
      appState.electrum = new ElectrumClient(appState.publicConfig.electrumUrl);
    } else {
      appState.electrum.close();
      appState.electrum = new ElectrumClient(appState.publicConfig.electrumUrl);
    }
    await appState.electrum.connect();
    appState.electrumConnected = true;
    setMessage(`Electrum connected: ${JSON.stringify(appState.electrum.serverInfo)}`, 'ok');
  } catch (err) {
    appState.electrumConnected = false;
    setMessage(`Electrum unavailable: ${err.message}`, 'error');
    throw err;
  } finally {
    render();
  }
}

async function scanBranch(branch, cfg, electrum, onProgress) {
  const records = [];
  let lastUsed = -1;
  let consecutiveUnused = 0;
  let index = 0;

  while (index < cfg.maxScan && consecutiveUnused < cfg.gapLimit) {
    const rec = deriveAddressRecord(appState.accountRoot, branch, index, cfg);
    const [history, unspent] = await Promise.all([
      electrum.getHistory(rec.scripthash).catch(() => []),
      electrum.listUnspent(rec.scripthash).catch(() => []),
    ]);
    rec.history = history;
    rec.unspent = unspent;
    rec.balance = {
      confirmed: unspent.filter((u) => (u.height || 0) > 0).reduce((sum, u) => sum + BigInt(u.value ?? 0), 0n),
      unconfirmed: unspent.filter((u) => (u.height || 0) <= 0).reduce((sum, u) => sum + BigInt(u.value ?? 0), 0n),
    };
    records.push(rec);

    if (isUsedRecord(rec)) {
      lastUsed = index;
      consecutiveUnused = 0;
    } else {
      consecutiveUnused++;
    }

    if (onProgress) onProgress(rec);
    index++;
  }

  return {
    records,
    lastUsed,
    nextIndex: lastUsed >= 0 ? lastUsed + 1 : 0,
  };
}

function attachSpendFields(utxo, rec, cfg) {
  const out = {
    txid: utxo.tx_hash,
    index: utxo.tx_pos,
    value: BigInt(utxo.value),
    height: utxo.height || 0,
    address: rec.address,
    branch: rec.branch,
    derivationIndex: rec.index,
    scripthash: rec.scripthash,
    pubKey: rec.pubKey,
    privKey: rec.privKey,
    script: rec.script,
    redeemScript: rec.redeemScript,
    payment: rec.payment,
    inputTemplate: null,
  };

  const network = networkFromConfig(cfg);
  if (cfg.addressType === 'p2wpkh') {
    out.inputTemplate = {
      witnessUtxo: { script: rec.script, amount: out.value },
    };
  } else if (cfg.addressType === 'p2sh-p2wpkh') {
    const inner = btc.p2wpkh(rec.pubKey, network);
    out.inputTemplate = {
      witnessUtxo: { script: rec.script, amount: out.value },
      redeemScript: inner.script,
    };
  } else {
    out.inputTemplate = {};
  }
  return out;
}

async function scanWallet() {
  if (!appState.electrum || !appState.accountRoot) throw new Error('Wallet is not ready');
  appState.syncBusy = true;
  render();
  const cfg = appState.publicConfig;
  const [external, change] = await Promise.all([
    scanBranch(0, cfg, appState.electrum),
    scanBranch(1, cfg, appState.electrum),
  ]);

  appState.externalRecords = external.records;
  appState.changeRecords = change.records;
  appState.nextExternalIndex = external.nextIndex;
  appState.nextChangeIndex = change.nextIndex;

  const utxos = [];
  for (const rec of [...external.records, ...change.records]) {
    for (const u of rec.unspent) {
      utxos.push(attachSpendFields(u, rec, cfg));
    }
  }
  appState.utxos = utxos;

  const balance = utxos.reduce((acc, u) => {
    if ((u.height || 0) > 0) acc.confirmed += u.value;
    else acc.unconfirmed += u.value;
    return acc;
  }, { confirmed: 0n, unconfirmed: 0n });
  appState.balance = balance;

  await subscribeAllTrackedScripthashes();

  const receive = getCurrentReceiveRecord();
  if (receive) {
    await loadExplorerForAddress(receive.address).catch(() => {});
  }

  appState.syncBusy = false;
  setMessage(`Synced ${external.records.length} external and ${change.records.length} change addresses`, 'ok');
}

async function subscribeAllTrackedScripthashes() {
  if (!appState.electrum || !appState.electrumConnected) return;
  const tracked = [...appState.externalRecords, ...appState.changeRecords];
  for (const rec of tracked) {
    try {
      await appState.electrum.subscribeScripthash(rec.scripthash, () => {
        if (!appState.pendingRefresh) {
          appState.pendingRefresh = true;
          setTimeout(async () => {
            appState.pendingRefresh = false;
            try {
              await syncWallet();
            } catch (err) {
              console.error(err);
            }
          }, 3000);
        }
      });
    } catch {
      // ignore
    }
  }
}

async function syncWallet() {
  if (!appState.unlocked) return;
  if (!appState.electrum) await connectElectrum();
  await scanWallet();
  render();
}

async function loadExplorerForAddress(address) {
  const base = normalizeExplorerBase(appState.publicConfig.explorerUrl);
  if (!base) return;
  try {
    const [balanceRes, txsRes] = await Promise.all([
      fetch(`${base}/ext/getbalance/${encodeURIComponent(address)}`).then((r) => r.json()),
      fetch(`${base}/ext/getaddresstxs/${encodeURIComponent(address)}/0/25`).then((r) => r.json()),
    ]);
    const balanceText = balanceRes && typeof balanceRes === 'object'
      ? `${balanceRes.confirmed ?? balanceRes.balance ?? '0'} / ${balanceRes.unconfirmed ?? '0'}`
      : JSON.stringify(balanceRes);
    appState.selectedAddressDetail = { address, balanceText, rawBalance: balanceRes };
    appState.explorerAddressTxs = Array.isArray(txsRes) ? txsRes : (txsRes?.txs || txsRes?.transactions || txsRes?.data || []);
  } catch (err) {
    console.warn('Explorer fetch failed', err);
    appState.selectedAddressDetail = { address, balanceText: 'unavailable', rawBalance: null };
    appState.explorerAddressTxs = [];
  }
  render();
}

async function onGenerateMnemonic() {
  try {
    const entropy = cryptoRandomBytes(16);
    const mnemonic = bip39.entropyToMnemonic(entropy, wordlist);
    appState.generatedMnemonic = mnemonic;
    setMessage('Mnemonic generated. Write it down offline before creating the vault.', 'ok');
  } catch (err) {
    setMessage(`Mnemonic generation failed: ${err.message}`, 'error');
  }
}

async function onCreateWallet() {
  try {
    const mnemonic = valueOf('generated-mnemonic').trim();
    const vaultPassword = valueOf('setup-vault-password');
    const bip39Passphrase = valueOf('setup-bip39-passphrase');
    const confirmed = document.getElementById('setup-confirm')?.checked;

    if (!mnemonic) throw new Error('Generate a mnemonic first');
    if (!confirmed) throw new Error('Confirm that you wrote the mnemonic offline');
    if (!vaultPassword) throw new Error('Vault password is required');
    if (!bip39.validateMnemonic(mnemonic, wordlist)) throw new Error('Mnemonic is invalid');

    const cfg = normalizePublicConfig(collectConfigFromForm());
    savePublicConfig(cfg);
    appState.publicConfig = cfg;

    const vault = await encryptVaultRecord(vaultPassword, {
      walletName: 'Main wallet',
      mnemonic,
      bip39Passphrase,
      config: cfg,
    });
    await saveVault(vault);

    appState.generatedMnemonic = '';
    await unlockWithWalletData({
      walletName: 'Main wallet',
      mnemonic,
      bip39Passphrase,
      config: cfg,
    }, vaultPassword);

    setMessage('Wallet created and unlocked successfully', 'ok');
  } catch (err) {
    setMessage(`Create failed: ${err.message}`, 'error');
  }
}

async function onRestoreWallet() {
  try {
    const mnemonic = valueOf('restore-mnemonic').trim().replace(/\s+/g, ' ');
    const vaultPassword = valueOf('restore-vault-password');
    const bip39Passphrase = valueOf('restore-bip39-passphrase');

    if (!mnemonic) throw new Error('Paste a mnemonic first');
    if (!vaultPassword) throw new Error('Vault password is required');
    if (!bip39.validateMnemonic(mnemonic, wordlist)) throw new Error('Mnemonic is invalid');

    const cfg = normalizePublicConfig(collectConfigFromForm());
    savePublicConfig(cfg);
    appState.publicConfig = cfg;

    const vault = await encryptVaultRecord(vaultPassword, {
      walletName: 'Main wallet',
      mnemonic,
      bip39Passphrase,
      config: cfg,
    });
    await saveVault(vault);

    await unlockWithWalletData({
      walletName: 'Main wallet',
      mnemonic,
      bip39Passphrase,
      config: cfg,
    }, vaultPassword);

    setMessage('Wallet restored and unlocked successfully', 'ok');
  } catch (err) {
    setMessage(`Restore failed: ${err.message}`, 'error');
  }
}

async function onUnlockWallet() {
  try {
    const vaultPassword = valueOf('unlock-password');
    if (!vaultPassword) throw new Error('Password is required');
    const vault = await loadVault();
    if (!vault) throw new Error('No vault found');
    const walletData = await decryptVaultRecord(vault, vaultPassword);
    await unlockWithWalletData(walletData, vaultPassword);
    setMessage('Vault unlocked', 'ok');
  } catch (err) {
    setMessage(`Unlock failed: ${err.message}`, 'error');
  }
}

async function onDeleteVault() {
  try {
    await deleteVault();
    setMessage('Vault deleted', 'ok');
    appState.unlocked = false;
    clearSecrets();
    if (appState.electrum) appState.electrum.close();
    appState.electrum = null;
    appState.electrumConnected = false;
    render();
  } catch (err) {
    setMessage(`Delete failed: ${err.message}`, 'error');
  }
}

async function onLockWallet() {
  try {
    if (appState.electrum) appState.electrum.close();
    appState.electrum = null;
    appState.electrumConnected = false;
    appState.unlocked = false;
    clearSecrets();
    setMessage('Wallet locked', 'ok');
    render();
  } catch (err) {
    setMessage(`Lock failed: ${err.message}`, 'error');
  }
}

async function onRefreshWallet() {
  try {
    setBusy(true);
    await connectElectrum();
    await syncWallet();
    setBusy(false);
  } catch (err) {
    setBusy(false);
    setMessage(`Refresh failed: ${err.message}`, 'error');
  }
}

function uniqueByInputKey(inputs, walletMap) {
  const privs = [];
  const seen = new Set();
  for (const input of inputs) {
    const id = `${normalizeTxId(input.txid)}:${input.index}`;
    const rec = walletMap.get(id);
    if (!rec || !rec.privKey) continue;
    const keyHex = bytesToHexLower(rec.privKey);
    if (!seen.has(keyHex)) {
      privs.push(rec.privKey);
      seen.add(keyHex);
    }
  }
  return privs;
}

async function enrichSelectedInputsForLegacy(selectedInputs, walletMap) {
  const out = [];
  for (const input of selectedInputs) {
    const id = `${normalizeTxId(input.txid)}:${input.index}`;
    const rec = walletMap.get(id);
    if (!rec) continue;
    const enriched = { ...input };
    if (appState.publicConfig.addressType === 'p2pkh') {
      if (!enriched.nonWitnessUtxo) {
        const raw = await appState.electrum.getTransaction(normalizeTxId(input.txid));
        enriched.nonWitnessUtxo = hexToBytesSafe(raw);
      }
    }
    if (appState.publicConfig.addressType === 'p2sh-p2wpkh') {
      enriched.redeemScript = rec.redeemScript;
    }
    out.push(enriched);
  }
  return out;
}

async function prepareSpendableInputs(selectedInputs, walletMap, cfg) {
  const out = [];
  for (const input of selectedInputs) {
    const id = `${normalizeTxId(input.txid)}:${input.index}`;
    const rec = walletMap.get(id);
    if (!rec) continue;

    const prepared = { ...input };

    if (cfg.addressType === 'p2pkh') {
      if (!prepared.nonWitnessUtxo) {
        const raw = await appState.electrum.getTransaction(normalizeTxId(input.txid));
        prepared.nonWitnessUtxo = hexToBytesSafe(raw);
      }
    } else if (cfg.addressType === 'p2sh-p2wpkh') {
      if (!prepared.redeemScript && rec.redeemScript) {
        prepared.redeemScript = rec.redeemScript;
      }
    }

    out.push(prepared);
  }
  return out;
}

async function onSendTransaction() {
  try {
    if (!appState.unlocked) throw new Error('Wallet is locked');
    if (!appState.electrumConnected) throw new Error('Electrum is offline');

    const recipient = valueOf('send-to').trim();
    const amountCoins = valueOf('send-amount').trim();
    const feeRate = Math.max(1, toInt(valueOf('send-fee-rate'), appState.publicConfig.feeRate));
    if (!recipient) throw new Error('Recipient address is required');
    const amount = coinsToSats(amountCoins);
    if (amount <= 0n) throw new Error('Amount must be greater than zero');

    const cfg = appState.publicConfig;
    const network = networkFromConfig(cfg);
    const walletMap = new Map();
    for (const u of appState.utxos) walletMap.set(`${normalizeTxId(u.txid)}:${u.index}`, u);

    let selectedInputs = appState.utxos.map((u) => ({
      txid: hexToBytesSafe(u.txid),
      index: u.index,
      amount: u.value,
      ...(u.inputTemplate || {}),
    }));

    selectedInputs = await prepareSpendableInputs(selectedInputs, walletMap, cfg);

    const nextChange = getCurrentChangeRecord();
    if (!nextChange) throw new Error('No change address available');

    const selected = btc.selectUTXO(
      selectedInputs,
      [{ address: recipient, amount }],
      'default',
      {
        changeAddress: nextChange.address,
        feePerByte: BigInt(feeRate),
        bip69: true,
        createTx: true,
        network,
      }
    );

    if (!selected) throw new Error('Insufficient funds');

    const tx = selected.tx;
    const selectedPrivKeys = uniqueByInputKey(tx.inputs, walletMap);
    for (const privKey of selectedPrivKeys) {
      tx.sign(privKey);
    }
    tx.finalize();
    const rawHex = tx.hex;
    const txid = tx.id;

    if (!rawHex || !txid) throw new Error('Transaction finalization failed');

    const broadcastId = await appState.electrum.broadcast(rawHex);
    appState.messageKind = 'send';
    appState.message = `Broadcast success: ${broadcastId}`;
    appState.nextChangeIndex += 1;
    setMessage(`Broadcast success: ${broadcastId}`, 'ok');
    await syncWallet();
  } catch (err) {
    setMessage(`Send failed: ${err.message}`, 'error');
  }
}

async function onSaveConfig() {
  try {
    if (appState.unlocked) {
      throw new Error('Lock the wallet before changing network config');
    }
    appState.publicConfig = normalizePublicConfig(collectConfigFromForm());
    savePublicConfig(appState.publicConfig);
    setMessage('Configuration saved', 'ok');
  } catch (err) {
    setMessage(`Config save failed: ${err.message}`, 'error');
  }
}

async function startup() {
  appState.vaultExists = await hasVault().catch(() => false);
  render();
  if (appState.vaultExists) {
    setMessage('Vault found. Unlock it, or create a new wallet if you want to replace it.', 'info');
  } else {
    setMessage('No vault found yet. Generate a mnemonic or restore an existing one.', 'info');
  }
}

window.addEventListener('beforeunload', () => {
  if (appState.electrum) appState.electrum.close();
  clearSecrets();
});

startup().catch((err) => {
  console.error(err);
  setMessage(`Startup failed: ${err.message}`, 'error');
});
